import os
import shutil
import sys
import subprocess
import tarfile
import zipfile

def create_backup(directory, format):
    if not os.path.isdir(directory):
        print("Invalid directory path.")
        return

    base_name = os.path.basename(os.path.normpath(directory))
    backup_name = f"{base_name}_backup"

    if format == 'tar.gz':
        with tarfile.open(f"{backup_name}.tar.gz", "w:gz") as tar:
            tar.add(directory, arcname=os.path.basename(directory))
    elif format == 'tar.bz2':
        with tarfile.open(f"{backup_name}.tar.bz2", "w:bz2") as tar:
            tar.add(directory, arcname=os.path.basename(directory))
    elif format == 'zip':
        with zipfile.ZipFile(f"{backup_name}.zip", 'w', zipfile.ZIP_DEFLATED) as zipf:
            for root, dirs, files in os.walk(directory):
                for file in files:
                    zipf.write(os.path.join(root, file), 
                                os.path.relpath(os.path.join(root, file), 
                                os.path.join(directory, '..')))
    elif format == '7z':
        if shutil.which('7z') is None:
            print("7z is not installed.")
            return
        subprocess.run(['7z', 'a', f"{backup_name}.7z", directory], check=True)
    else:
        print("Unsupported format. Use tar.gz, tar.bz2, zip, or 7z.")
        return

    print(f"Backup created: {backup_name}.{format}")

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
        sys.exit(1)

    dir_path = sys.argv[1]
    backup_format = sys.argv[2]
    create_backup(dir_path, backup_format)